import React, { useState, useRef } from 'react';

const FileUpload = ({ onFileProcessed, theme, isLoading: parentLoading }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [dragActive, setDragActive] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const fileInputRef = useRef(null);

  const supportedTypes = [
    'application/pdf',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    'application/msword',
    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    'application/vnd.ms-excel',
    'application/vnd.openxmlformats-officedocument.presentationml.presentation',
    'application/vnd.ms-powerpoint',
    'text/plain',
    'image/jpeg',
    'image/png',
    'image/gif',
    'image/bmp',
    'image/tiff',
    'image/webp'
  ];

  const getFileIcon = (type) => {
    if (type.includes('pdf')) return '📄';
    if (type.includes('word') || type.includes('document')) return '📝';
    if (type.includes('sheet') || type.includes('excel')) return '📊';
    if (type.includes('presentation') || type.includes('powerpoint')) return '📽️';
    if (type.includes('image')) return '🖼️';
    if (type.includes('text')) return '📃';
    return '📁';
  };

  const handleFiles = async (files) => {
    const file = files[0];
    if (!file) return;

    // Validate file type
    if (!supportedTypes.includes(file.type)) {
      alert('File type not supported! Please upload PDF, Word, Excel, PowerPoint, or image files.');
      return;
    }

    // Validate file size (16MB limit)
    if (file.size > 16 * 1024 * 1024) {
      alert('File size too large! Please upload files smaller than 16MB.');
      return;
    }

    setIsUploading(true);
    setUploadProgress(0);

    try {
      const formData = new FormData();
      formData.append('file', file);

      // Simulate upload progress
      const progressInterval = setInterval(() => {
        setUploadProgress(prev => {
          if (prev >= 90) {
            clearInterval(progressInterval);
            return 90;
          }
          return prev + 10;
        });
      }, 200);

      const response = await fetch('/api/files/upload', {
        method: 'POST',
        body: formData,
      });

      clearInterval(progressInterval);
      setUploadProgress(100);

      const result = await response.json();

      if (result.success) {
        onFileProcessed(result);
      } else {
        throw new Error(result.error || 'Upload failed');
      }

    } catch (error) {
      console.error('File upload error:', error);
      alert(`Upload failed: ${error.message}`);
    } finally {
      setIsUploading(false);
      setUploadProgress(0);
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    }
  };

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true);
    } else if (e.type === 'dragleave') {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFiles(e.dataTransfer.files);
    }
  };

  const handleInputChange = (e) => {
    if (e.target.files && e.target.files[0]) {
      handleFiles(e.target.files);
    }
  };

  const openFileDialog = () => {
    fileInputRef.current?.click();
  };

  const isDisabled = isUploading || parentLoading;

  return (
    <div className={`file-upload-container ${theme}`}>
      {/* Hidden file input */}
      <input
        ref={fileInputRef}
        type="file"
        onChange={handleInputChange}
        accept=".pdf,.docx,.doc,.xlsx,.xls,.pptx,.ppt,.txt,.jpg,.jpeg,.png,.gif,.bmp,.tiff,.webp"
        style={{ display: 'none' }}
        disabled={isDisabled}
      />

      {/* Upload button */}
      <button
        className="file-upload-btn"
        onClick={openFileDialog}
        disabled={isDisabled}
        title="Upload files (PDF, Word, Excel, PowerPoint, Images)"
      >
        {isUploading ? (
          <div className="upload-progress">
            <div className="spinner-small"></div>
            <span>{uploadProgress}%</span>
          </div>
        ) : (
          <>
            <span className="upload-icon">📎</span>
          </>
        )}
      </button>

      {/* Drag and drop overlay */}
      <div
        className={`drag-drop-overlay ${dragActive ? 'active' : ''}`}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
      >
        <div className="drag-drop-content">
          <div className="drag-icon">📁</div>
          <p>Drop your files here</p>
          <p className="drag-subtitle">PDF, Word, Excel, PowerPoint, Images</p>
        </div>
      </div>
    </div>
  );
};

export default FileUpload;
